                {/* ═══════════════ Webhook ═══════════════ */}
                <ModernCard style={styles.card}>
                    <View style={styles.cardHeader}>
                        <Text style={styles.cardIcon}>🔗</Text>
                        <Text style={styles.cardTitle}>Webhook</Text>
                        <Switch
                            value={settings.webhook_enabled}
