/**
 * Dashboard Screen - شاشة لوحة التحكم
 * Main dashboard showing portfolio and trading overview
 */

import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import {
    View,
    Text,
    ScrollView,
    StyleSheet,
    ActivityIndicator,
    RefreshControl,
    I18nManager,
    TouchableOpacity,
    Image,
} from 'react-native';
// ActivityIndicator موجود بالفعل
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useNavigation } from '@react-navigation/native';
import DatabaseApiService from '../services/DatabaseApiService';
import { theme } from '../theme/theme';
import { SafeAreaView } from 'react-native-safe-area-context';
import { colors, spacing, typography, textStyles, components, shadows } from '../theme/designSystem';
import { useBackHandlerWithConfirmation } from '../utils/BackHandlerUtil';
import ToastService from '../services/ToastService';
import { DemoModeIcon, RealModeIcon } from '../components/TradingModeIcons';
import ModernCard from '../components/ModernCard';
import MiniPortfolioChart from '../components/charts/MiniPortfolioChart';
import WinLossPieChart from '../components/charts/WinLossPieChart';
import ActivePositionsCard from '../components/ActivePositionsCard';
// ✅ تم إزالة QualifiedCoinsCard - كانت تسبب خطأ 404
import { useTradingModeContext } from '../context/TradingModeContext';
import { usePortfolioContext } from '../context/PortfolioContext';
import UnifiedBrandLogo from '../components/UnifiedBrandLogo';
import GlobalHeader from '../components/GlobalHeader';
import BrandIcon from '../components/BrandIcons';
import { DashboardSkeleton } from '../components/SkeletonLoader';
import { hapticLight, hapticSuccess, hapticWarning } from '../utils/HapticFeedback';
import { AlertService } from '../components/CustomAlert';
import { useIsAdmin } from '../hooks/useIsAdmin';
import AdminModeBanner from '../components/AdminModeBanner';
import { appStateManager, AppEvents } from '../services/AppStateManager';
// ✅ AdminModeSwitcher تم نقله إلى GlobalHeader

const isRTL = I18nManager.isRTL;

const DashboardScreen = ({ user: propUser }) => {
    const navigation = useNavigation();
    const [user, setUser] = useState(propUser || null);
    const [stats, setStats] = useState(null);
    const [loading, setLoading] = useState(true);
    const [refreshing, setRefreshing] = useState(false);
    const [lastUpdated, setLastUpdated] = useState(new Date());
    const [hasKeys, setHasKeys] = useState(null); // ✅ null حتى جلب البيانات الحقيقية - لا افتراضات
    const [qualifiedCoins, setQualifiedCoins] = useState([]); // العملات المؤهلة
    const [activePositions, setActivePositions] = useState([]);
    const [positionsSummary, setPositionsSummary] = useState({});
    const [positionsLoading, setPositionsLoading] = useState(false);

    // ✅ إصلاح Race Conditions - منع تحديث State على unmounted component
    const isMountedRef = useRef(true);

    // ✅ Cleanup عند unmount
    useEffect(() => {
        isMountedRef.current = true;
        return () => {
            isMountedRef.current = false;
        };
    }, []);

    // ✅ استخدام PortfolioContext بدلاً من state محلي
    const {
        portfolio,
        demoPortfolio,
        realPortfolio,
        isLoading: portfolioLoading,
        fetchAllPortfolios,
        refreshPortfolios,
        updateUser: updatePortfolioUser
    } = usePortfolioContext();

    // ✅ للأدمن: ملخص المحفظتين من Context
    const adminPortfolios = {
        demo: demoPortfolio,
        real: realPortfolio,
    };

    // ✅ استخدام Context الموحد لوضع التداول
    const {
        tradingMode,
        getModeText,
        getModeColor,
        refreshCounter,
        initializeUser,
        isAdmin: contextIsAdmin,
        getCurrentViewMode,
        adminViewMode,
        changeTradingMode,
        isLoading: modeLoading,
        hasBinanceKeys,
    } = useTradingModeContext();

    const [switching, setSwitching] = useState(false);

    // ✅ الوضع الفعلي للعرض (للأدمن يمكن أن يختلف عن tradingMode)
    const currentViewMode = getCurrentViewMode();

    // ✅ معالجة زر الرجوع من الجهاز - عرض Dialog تأكيد قبل الخروج
    useBackHandlerWithConfirmation(true);

    useEffect(() => {
        // استخدام user من props أو من AsyncStorage
        if (propUser) {
            setUser(propUser);
            initializeUser(propUser);
            const isAdminUser = propUser.user_type === 'admin';
            updatePortfolioUser(propUser.id, isAdminUser);
            loadDashboardData();
        }
    }, [propUser]);

    // ✅ إعادة تحميل البيانات عند تغيير وضع التداول (مع debounce لمنع 429)
    useEffect(() => {
        if (refreshCounter > 0 && user) {
            // ✅ تأخير عشوائي لمنع الطلبات المتزامنة (429 Rate Limit)
            const delay = Math.random() * 500 + 200; // 200-700ms
            const timer = setTimeout(() => {
                loadDashboardData();
            }, delay);
            return () => clearTimeout(timer);
        }
    }, [refreshCounter, user]);

    // ✅ الاستماع لتغييرات حالة النظام وتحديث البيانات تلقائياً
    useEffect(() => {
        // الاستماع لتغيير حالة النظام (من AdminDashboard)
        const unsubSystemStatus = appStateManager.on(AppEvents.SYSTEM_STATUS_CHANGED, (status) => {
            if (isMountedRef.current) {
                console.log('[DashboardScreen] System status changed:', status.is_running ? 'running' : 'stopped');
                // تحديث البيانات عند تغيير حالة النظام
                loadDashboardData();
            }
        });

        // الاستماع لطلب تحديث إجباري
        const unsubForceRefresh = appStateManager.on(AppEvents.FORCE_REFRESH, () => {
            if (isMountedRef.current) {
                console.log('[DashboardScreen] Force refresh triggered');
                loadDashboardData();
            }
        });

        // الاستماع لتغيير وضع التداول
        const unsubModeChange = appStateManager.on(AppEvents.TRADING_MODE_CHANGED, ({ mode }) => {
            if (isMountedRef.current) {
                console.log('[DashboardScreen] Trading mode changed to:', mode);
                loadDashboardData();
            }
        });

        return () => {
            unsubSystemStatus();
            unsubForceRefresh();
            unsubModeChange();
        };
    }, [loadDashboardData]);

    // ✅ Live Dashboard: تحديث تلقائي للصفقات النشطة كل 30 ثانية
    const positionsIntervalRef = useRef(null);
    useEffect(() => {
        if (!user) return;

        // تحديث الصفقات النشطة كل 30 ثانية
        positionsIntervalRef.current = setInterval(() => {
            if (isMountedRef.current && user) {
                loadActivePositions(user);
            }
        }, 30000); // 30 ثانية

        return () => {
            if (positionsIntervalRef.current) {
                clearInterval(positionsIntervalRef.current);
            }
        };
    }, [user, loadActivePositions]);

    const loadDashboardData = useCallback(async () => {
        // ✅ فحص isMounted قبل البدء
        if (!isMountedRef.current) return;

        try {
            setLoading(true);

            // استخدام user من props أو من AsyncStorage
            let currentUser = user || propUser;

            if (!currentUser) {
                const userData = await AsyncStorage.getItem('userData');
                if (!userData) {
                    if (isMountedRef.current) {
                        ToastService.showInfo('لم يتم العثور على بيانات المستخدم');
                        setLoading(false);
                    }
                    return;
                }
                try {
                    currentUser = JSON.parse(userData);
                } catch (parseError) {
                    console.error('[CRASH_PREVENTION] فشل تحليل بيانات المستخدم:', parseError);
                    if (isMountedRef.current) {
                        ToastService.showError('بيانات المستخدم تالفة، يرجى تسجيل الدخول مرة أخرى');
                        setLoading(false);
                    }
                    return;
                }
            }

            // ✅ فحص isMounted بعد كل عملية async
            if (!isMountedRef.current) return;

            // ✅ جلب الملف الشخصي للحصول على الاسم الكامل
            try {
                const profileData = await DatabaseApiService.getProfile(currentUser.id);
                if (isMountedRef.current && profileData?.success && profileData?.data) {
                    currentUser = { ...currentUser, ...profileData.data };
                }
            } catch (e) {
                console.warn('[WARNING] فشل جلب الملف الشخصي');
            }

            if (!isMountedRef.current) return;
            setUser(currentUser);

            // تهيئة خدمة قاعدة البيانات
            await DatabaseApiService.initialize();

            if (!isMountedRef.current) return;

            // ✅ جلب بيانات المحفظة من Context (مع Cache)
            await fetchAllPortfolios();

            if (!isMountedRef.current) return;

            // تحديث hasKeys من portfolio (بيانات حقيقية فقط)
            if (portfolio && portfolio.hasKeys !== undefined) {
                setHasKeys(portfolio.hasKeys === true);
            } else {
                setHasKeys(null); // null حتى جلب البيانات الحقيقية
            }

            // ✅ جلب الإحصائيات حسب الوضع الحالي
            const userIsAdmin = currentUser?.user_type === 'admin';
            const statsData = await DatabaseApiService.getStats(
                currentUser.id,
                userIsAdmin ? currentViewMode : null
            );

            if (!isMountedRef.current) return;

            if (statsData?.success && statsData?.data) {
                setStats(statsData.data);
            } else {
                // ✅ رسالة دقيقة حسب سبب الخطأ
                if (statsData?.errorCode === 401) {
                    console.warn('[WARNING] انتهت صلاحية الجلسة - يرجى إعادة تسجيل الدخول');
                } else {
                    console.warn('[WARNING] الإحصائيات غير متاحة مؤقتاً');
                }
                setStats(null);
            }

            // ✅ جلب العملات المؤهلة
            try {
                const coinsData = await DatabaseApiService.getQualifiedCoins(currentUser.id);
                if (isMountedRef.current && coinsData?.success && coinsData?.data?.coins) {
                    setQualifiedCoins(coinsData.data.coins.slice(0, 5)); // أول 5 عملات
                }
            } catch (e) {
                console.warn('[WARNING] العملات المؤهلة غير متاحة');
            }

            if (!isMountedRef.current) return;

            // ✅ جلب الصفقات النشطة
            await loadActivePositions(currentUser);

            if (isMountedRef.current) {
                setLastUpdated(new Date());
            }
        } catch (error) {
            console.error('[ERROR] خطأ في تحميل بيانات لوحة التحكم:', error);
            if (isMountedRef.current) {
                ToastService.showInfo('فشل تحميل البيانات');
            }
        } finally {
            if (isMountedRef.current) {
                setLoading(false);
            }
        }
    }, [user, propUser, portfolio, fetchAllPortfolios, currentViewMode]);

    const loadActivePositions = useCallback(async (currentUser) => {
        // ✅ فحص isMounted قبل البدء
        if (!isMountedRef.current) return;

        try {
            if (!currentUser || !currentUser.id) {
                console.warn('[WARNING] لا يوجد مستخدم أو معرف مستخدم');
                if (isMountedRef.current) {
                    setActivePositions([]);
                    setPositionsSummary({});
                }
                return;
            }

            setPositionsLoading(true);
            const userIsAdmin = currentUser?.user_type === 'admin';
            const mode = userIsAdmin ? currentViewMode : null;
            const positionsData = await DatabaseApiService.getActivePositions(currentUser.id, mode);

            if (!isMountedRef.current) return;

            if (positionsData?.success && positionsData?.data) {
                setActivePositions(positionsData.data.positions || []);
                setPositionsSummary(positionsData.data.summary || {});
            } else {
                setActivePositions([]);
                setPositionsSummary({});
            }
        } catch (error) {
            console.error('[ERROR] خطأ في جلب الصفقات النشطة:', error);
            if (isMountedRef.current) {
                setActivePositions([]);
                setPositionsSummary({});
            }
        } finally {
            if (isMountedRef.current) {
                setPositionsLoading(false);
            }
        }
    }, [currentViewMode]);

    const onRefresh = useCallback(async () => {
        if (!isMountedRef.current) return;
        setRefreshing(true);
        await loadDashboardData();
        if (isMountedRef.current) {
            setRefreshing(false);
        }
    }, [loadDashboardData]);

    // فحص إذا كان المستخدم أدمن - ✅ استخدام Hook موحد
    const isAdmin = useIsAdmin(user);
    const modeColor = getModeColor?.() || '#4A90E2';

    // ✅ دالة تنفيذ التبديل
    const executeToggle = useCallback(async (newMode) => {
        setSwitching(true);
        hapticLight();
        try {
            const result = await changeTradingMode(newMode);
            if (result?.success) {
                hapticSuccess();
                ToastService.showSuccess(`تم التبديل إلى ${newMode === 'demo' ? 'التجريبي' : 'الحقيقي'}`);
            } else {
                hapticWarning();
                ToastService.showError(result?.error || 'فشل التبديل');
            }
        } catch (error) {
            hapticWarning();
            ToastService.showError('حدث خطأ');
        } finally {
            setSwitching(false);
        }
    }, [changeTradingMode]);

    // ✅ دالة تبديل الوضع للأدمن
    const handleToggleMode = useCallback(async () => {
        if (!isAdmin || switching || modeLoading) return;

        const newMode = currentViewMode === 'demo' ? 'real' : 'demo';

        if (newMode === 'real') {
            if (!hasBinanceKeys) {
                hapticWarning();
                ToastService.showWarning('يجب إضافة مفاتيح Binance أولاً');
                return;
            }

            AlertService.confirm(
                '⚠️ تحذير هام',
                'أنت على وشك التبديل للتداول الحقيقي.\n\nجميع الصفقات ستكون حقيقية.',
                async () => { await executeToggle(newMode); },
                () => { },
                'تأكيد',
                'إلغاء'
            );
        } else {
            await executeToggle(newMode);
        }
    }, [isAdmin, switching, modeLoading, currentViewMode, hasBinanceKeys, executeToggle]);

    // تثبيت قيم الشارت لتجنب إعادة الحساب المستمرة - ✅ بيانات حقيقية فقط (بدون بيانات افتراضية)
    const chartBalance = useMemo(() => {
        const balance = parseFloat(portfolio?.totalBalance);
        return !isNaN(balance) ? balance : null;
    }, [portfolio?.totalBalance]);

    const chartInitialBalance = useMemo(() => {
        const balance = parseFloat(portfolio?.initialBalance);
        return !isNaN(balance) ? balance : null;
    }, [portfolio?.initialBalance]);

    // ✅ عرض Skeleton Loader بدلاً من ActivityIndicator
    if (loading) {
        return (
            <View style={styles.container}>
                <DashboardSkeleton />
            </View>
        );
    }

    return (
        <View style={styles.container}>
            {/* ✅ استخدام GlobalHeader الموحد */}
            <GlobalHeader
                title="1B Trading"
                subtitle={`مرحباً، ${user?.name || user?.username || 'متداول'}`}
                showLogo={true}
                isAdminUser={isAdmin}
                rightAction={
                    <View style={{ flexDirection: isRTL ? 'row-reverse' : 'row', alignItems: 'center', gap: 8 }}>
                        <TouchableOpacity
                            style={styles.notificationBtn}
                            onPress={() => { hapticLight(); navigation.navigate('Notifications'); }}
                            activeOpacity={0.7}
                        >
                            <BrandIcon name="notification" size={24} color={theme.colors.text} />
                        </TouchableOpacity>
                        <TouchableOpacity
                            style={styles.settingsBtn}
                            onPress={() => { hapticLight(); navigation.navigate('Profile'); }}
                            activeOpacity={0.7}
                        >
                            <BrandIcon name="settings" size={22} color={theme.colors.textSecondary} />
                        </TouchableOpacity>
                    </View>
                }
            />

            {/* ✅ Banner تحذيري للأدمن فقط - مع تمرير وضع التداول */}
            {isAdmin && <AdminModeBanner tradingMode={tradingMode} />}

            <ScrollView
                contentContainerStyle={styles.scrollContent}
                refreshControl={<RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={theme.colors.primary} />}
            >
                {/* ✅ تحذير واضح في بداية Dashboard - تمييز كامل بين الأدمن والمستخدم */}
                <ModernCard variant="warning" style={styles.dashboardWarningCard}>
                    <View style={styles.warningHeader}>
                        <BrandIcon name="exclamation-triangle" size={24} color={theme.colors.warning} />
                        <Text style={[styles.warningTitle, { color: theme.colors.warning }]}>
                            ⚠️ توضيح مهم
                        </Text>
                    </View>
                    <Text style={styles.warningText}>
                        {isAdmin
                            ? '🔴 أنت في الوضع التجريبي (Demo Mode) - جميع البيانات تجريبية للاختبار فقط'
                            : (tradingMode === 'demo'
                                ? '📊 جميع البيانات المعروضة هي بيانات تجريبية للاختبار فقط'
                                : '💰 البيانات حقيقية من Binance - النظام يتداول آلياً')
                        }
                    </Text>
                    {isAdmin && (
                        <View style={styles.adminModeIndicator}>
                            <Text style={styles.adminModeText}>
                                👨‍💼 وضع الأدمن: {tradingMode === 'demo' ? 'تجريبي آمن' : 'حقيقي مع مفاتيح'}
                            </Text>
                        </View>
                    )}
                </ModernCard>

                {/* 1️⃣ بطاقة الرصيد + شارت المحفظة */}
                <ModernCard style={styles.heroCard}>
                    <View style={styles.balanceSection}>
                        <Text style={styles.balanceLabel}>الرصيد الإجمالي</Text>
                        <Text style={styles.balanceValue}>
                            {chartBalance !== null ? chartBalance.toFixed(2) : '⏳ جاري التحقق...'} <Text style={styles.currency}>USDT</Text>
                        </Text>
                        {chartInitialBalance && chartBalance && (
                            <Text style={[styles.pnlBadge, {
                                color: chartBalance >= chartInitialBalance ? theme.colors.success : theme.colors.error
                            }]}>
                                {chartBalance >= chartInitialBalance ? '▲' : '▼'} {((chartBalance - chartInitialBalance) / chartInitialBalance * 100).toFixed(2)}%
                            </Text>
                        )}
                    </View>

                    {/* ✅ الشارت مباشرة تحت الرصيد */}
                    <View style={styles.chartInCard}>
                        <MiniPortfolioChart
                            userId={user?.id}
                            currentBalance={chartBalance}
                            isAdmin={isAdmin}
                            tradingMode={tradingMode}
                        />
                    </View>
                </ModernCard>

                {/* 3️⃣ Win/Loss Pie Chart - معدل النجاح */}
                {user && (
                    <View style={styles.chartContainer}>
                        <WinLossPieChart
                            userId={user?.id}
                            isAdmin={isAdmin}
                            tradingMode={tradingMode}
                        />
                    </View>
                )}

                {/* 3️⃣ الصفقات النشطة - بطاقة جديدة */}
                {user && (
                    <ActivePositionsCard
                        positions={activePositions}
                        summary={positionsSummary}
                        loading={positionsLoading}
                        onRefresh={() => loadActivePositions(user)}
                    />
                )}

                {/* 3️⃣ العملات النشطة - للأدمن فقط (المستخدم العادي لا يستفيد من هذه المعلومات) */}
                {isAdmin && qualifiedCoins.length > 0 && (
                    <ModernCard style={styles.coinsCard}>
                        <View style={styles.coinsSectionHeader}>
                            <Text style={styles.sectionTitle}>العملات قيد المراقبة</Text>
                            <Text style={styles.coinsCount}>{qualifiedCoins.length} عملة</Text>
                        </View>
                        <Text style={styles.coinsHint}>النظام يراقب هذه العملات للتداول الآلي</Text>
                        {qualifiedCoins.map((coin, index) => {
                            const symbol = (coin.symbol?.replace('USDT', '') || coin).toUpperCase();
                            const rank = index + 1;
                            return (
                                <View key={index} style={styles.coinDetailRow}>
                                    <View style={styles.coinMainInfo}>
                                        <View style={styles.coinRankBadge}>
                                            <Text style={styles.coinRankText}>{rank}</Text>
                                        </View>
                                        <Text style={styles.coinSymbolLarge}>{symbol}</Text>
                                    </View>
                                    <View style={styles.coinStats}>
                                        <View style={styles.coinStatItem}>
                                            <Text style={[styles.coinStatValue, { color: (coin.profit_pct || 0) >= 0 ? theme.colors.success : theme.colors.error }]}>
                                                {(coin.profit_pct || 0) >= 0 ? '+' : ''}{(coin.profit_pct || 0).toFixed(0)}%
                                            </Text>
                                            <Text style={styles.coinStatLabel}>الربح</Text>
                                        </View>
                                        <View style={styles.coinStatItem}>
                                            <Text style={[styles.coinStatValue, { color: (coin.win_rate || 0) >= 60 ? theme.colors.success : theme.colors.warning }]}>
                                                {(coin.win_rate || 0).toFixed(0)}%
                                            </Text>
                                            <Text style={styles.coinStatLabel}>النجاح</Text>
                                        </View>
                                    </View>
                                </View>
                            );
                        })}
                    </ModernCard>
                )}

                {/* 3️⃣ الإحصائيات السريعة - مع معالجة حالة عدم وجود صفقات */}
                <ModernCard style={styles.statsCard}>
                    <Text style={styles.sectionTitle}>ملخص الأداء</Text>
                    {parseInt(stats?.totalTrades || 0) === 0 ? (
                        <View style={styles.noTradesContainer}>
                            <BrandIcon name="chart" size={32} color={theme.colors.textSecondary} />
                            <Text style={styles.noTradesText}>لا توجد صفقات بعد</Text>
                            <Text style={styles.noTradesHint}>النظام يعمل آلياً وسيبدأ التداول عند توفر فرص مناسبة</Text>
                        </View>
                    ) : (
                        <View style={styles.quickStatsRow}>
                            <View style={styles.quickStatItem}>
                                <Text style={[
                                    styles.quickStatValue,
                                    { color: parseFloat(stats?.totalProfit || 0) >= 0 ? theme.colors.success : theme.colors.error }
                                ]}>
                                    ${stats?.totalProfit || '0.00'}
                                </Text>
                                <Text style={styles.quickStatLabel}>إجمالي الربح</Text>
                                {/* ✅ شارة توضيح مصدر البيانات */}
                                <Text style={styles.dataSourceBadge}>
                                    من: {isDemoData ? '📊 قاعدة البيانات التجريبية' : '💰 Binance API'}
                                </Text>
                            </View>
                            <View style={styles.quickStatDivider} />
                            <View style={styles.quickStatItem}>
                                <Text style={[styles.quickStatValue, { color: parseFloat(stats?.winRate || 0) >= 50 ? theme.colors.success : theme.colors.warning }]}>
                                    {stats?.winRate || '0'}%
                                </Text>
                                {/* ✅ إضافة شارة توضيحية للبيانات التجريبية */}
                                <Text style={styles.dataTypeBadge}>
                                    {tradingMode === 'demo' ? '📊 بيانات تجريبية' : '💰 بيانات حقيقية'}
                                </Text>
                                <Text style={styles.quickStatLabel}>نسبة النجاح</Text>
                                {/* ✅ شارة توضيح مصدر البيانات */}
                                <Text style={styles.dataSourceBadge}>
                                    من: {isDemoData ? '📊 قاعدة البيانات التجريبية' : '💰 Binance API'}
                                </Text>
                            </View>
                            <View style={styles.quickStatDivider} />
                            <View style={styles.quickStatItem}>
                                <Text style={styles.quickStatValue}>{stats?.totalTrades || '0'}</Text>
                                <Text style={styles.quickStatLabel}>صفقة</Text>
                            </View>
                        </View>
                    )}
                </ModernCard>

                {/* 4️⃣ حالة النظام - معلومات حول Group A و Group B */}
                <ModernCard style={styles.systemStatusCard}>
                    <View style={styles.sectionHeader}>
                        <BrandIcon name="settings" size={22} color={theme.colors.primary} />
                        <Text style={styles.sectionTitle}>حالة النظام</Text>
                    </View>

                    <View style={styles.systemStatusRow}>
                        <View style={styles.systemStatusItem}>
                            <View style={styles.systemStatusHeader}>
                                <BrandIcon name="cpu" size={18} color={theme.colors.info} />
                                <Text style={styles.systemStatusTitle}>Group A System</Text>
                            </View>
                            <Text style={styles.systemStatusValue}>
                                {isDemoData ? '📊 وضع تجريبي' : '💰 وضع حقيقي'}
                            </Text>
                            <Text style={styles.systemStatusDescription}>
                                • اختيار العملات{'\n'}
                                • تحديث كل 12 ساعة{'\n'}
                                • الحالة: نشط
                            </Text>
                        </View>

                        <View style={styles.systemStatusDivider} />

                        <View style={styles.systemStatusItem}>
                            <View style={styles.systemStatusHeader}>
                                <BrandIcon name="activity" size={18} color={theme.colors.success} />
                                <Text style={styles.systemStatusTitle}>Group B System</Text>
                            </View>
                            <Text style={styles.systemStatusValue}>
                                {isDemoData ? '📊 وضع تجريبي' : '💰 وضع حقيقي'}
                            </Text>
                            <Text style={styles.systemStatusDescription}>
                                • إدارة الصفقات{'\n'}
                                • تحديث كل 60 ثانية{'\n'}
                                • الحالة: نشط
                            </Text>
                        </View>
                    </View>

                    <View style={styles.systemStatusFooter}>
                        <Text style={styles.systemStatusLastUpdate}>
                            آخر تحديث: {new Date().toLocaleString('ar-SA')}
                        </Text>
                        <Text style={styles.systemStatusNote}>
                            {isAdmin
                                ? '🔴 ملاحظة: جميع البيانات تجريبية للاختبار'
                                : (tradingMode === 'demo'
                                    ? '📊 ملاحظة: النظام في وضع تجريبي'
                                    : '💰 ملاحظة: النظام يتداول بأموال حقيقية')
                            }
                        </Text>
                    </View>
                </ModernCard>

                {/* 3️⃣ تحذير للأدمن - في الأسفل */}
                {isAdmin && (
                    <ModernCard
                        variant={tradingMode === 'demo' ? 'warning' : 'success'}
                        style={styles.adminBanner}
                    >
                        <View style={styles.adminWarningContent}>
                            <View style={styles.iconContainer}>
                                {tradingMode === 'demo' ? (
                                    <DemoModeIcon size={24} color={modeColor} />
                                ) : (
                                    <RealModeIcon size={24} color={modeColor} />
                                )}
                            </View>
                            <View style={styles.textContainer}>
                                <Text style={[styles.adminWarningTitle, { color: modeColor }]}>
                                    {tradingMode === 'demo'
                                        ? 'جميع البيانات وهمية للاختبار'
                                        : (hasBinanceKeys
                                            ? 'البيانات حقيقية من Binance - النظام يتداول آلياً'
                                            : '⚠️ أضف مفاتيح Binance للتداول الحقيقي')}
                                </Text>
                            </View>
                        </View>
                    </ModernCard>
                )}

                {/* 4️⃣ بطاقة ربط Binance - للمستخدم بدون مفاتيح */}
                {!isAdmin && !hasKeys && (
                    <ModernCard variant="warning" style={styles.setupCard}>
                        <View style={styles.setupCardContent}>
                            <View style={styles.setupIconContainer}>
                                <BrandIcon name="key" size={32} color={theme.colors.warning} />
                            </View>
                            <View style={styles.setupTextContainer}>
                                <Text style={styles.setupTitle}>ربط Binance للتداول الحقيقي</Text>
                                <Text style={styles.setupDescription}>
                                    لبدء التداول الآلي، تحتاج لربط حسابك على Binance.
                                </Text>
                            </View>
                        </View>

                        <TouchableOpacity
                            style={styles.setupButton}
                            onPress={() => { hapticLight(); navigation.navigate('Trading', { screen: 'BinanceKeys' }); }}
                            activeOpacity={0.8}
                        >
                            <BrandIcon name="link" size={16} color={theme.colors.background} />
                            <Text style={styles.setupButtonText}>ربط حساب Binance</Text>
                        </TouchableOpacity>
                    </ModernCard>
                )}

                <View style={{ height: 20 }} />
            </ScrollView>
        </View>
    );
};

