                </Text>

                {/* قائمة الصلاحيات */}
                <View style={styles.permissionsList}>
                    <PermissionItem
                        icon="notification"
                        title="الإشعارات"
                        description="لإعلامك بالصفقات والتحديثات المهمة"
                        status={permissions.notifications}
                    />
                    <PermissionItem
                        icon="shield"
                        title="الأمان"
                        description="لحماية حسابك باستخدام البصمة"
                        status={permissions.camera}
                    />
                    <PermissionItem
                        icon="settings"
                        title="التخزين"
                        description="لحفظ إعداداتك وبياناتك محلياً"
                        status={permissions.storage}
                    />
                </View>

                {/* الأزرار */}
                <View style={styles.buttonsContainer}>
                    <TouchableOpacity
                        style={[styles.primaryButton, loading && styles.buttonDisabled]}
                        onPress={handleRequestPermissions}
                        disabled={loading}
                    >
                        <LinearGradient
                            colors={[BRAND_COLORS.primary, BRAND_COLORS.secondary]}
                            start={{ x: 0, y: 0 }}
                            end={{ x: 1, y: 0 }}
                            style={styles.buttonGradient}
                        >
                            <Text style={styles.primaryButtonText}>
                                {loading ? 'جاري الطلب...' : 'السماح بالصلاحيات'}
                            </Text>
                        </LinearGradient>
                    </TouchableOpacity>

                    <TouchableOpacity
                        style={styles.skipButton}
                        onPress={handleSkip}
                        disabled={loading}
                    >
                        <Text style={styles.skipButtonText}>تخطي الآن</Text>
                    </TouchableOpacity>
                </View>

                {/* ملاحظة */}
                <Text style={styles.note}>
                    يمكنك تغيير هذه الإعدادات لاحقاً من إعدادات الجهاز
                </Text>
            </ScrollView>
        </SafeAreaView>
    );
};

