                    <View style={styles.infoRow}>
                        <Text style={styles.infoLabel}>العملة</Text>
                        <Text style={styles.infoValue}>
                            {portfolio?.currency || 'USDT'}
                            {/* ✅ شارة توضيح مصدر البيانات */}
                            <Text style={styles.dataSourceBadge}>
                                {' '}(من: {isDemoData ? '📊 قاعدة البيانات التجريبية' : '💰 Binance API'})
                            </Text>
                        </Text>
                    </View>

                    <View style={styles.infoRow}>
                        <Text style={styles.infoLabel}>آخر تحديث</Text>
                        <Text style={styles.infoValue}>
                            {portfolio?.lastUpdate
                                ? new Date(portfolio.lastUpdate).toLocaleString('ar-SA', {
                                    hour: '2-digit',
                                    minute: '2-digit',
                                    day: 'numeric',
                                    month: 'short'
                                })
                                : 'الآن'}
                        </Text>
                    </View>
                </ModernCard>

                <View style={{ height: 30 }} />
            </ScrollView>
        </View>
    );
};

