        tip: '3-5 صفقات موصى به',
        thresholds: { warning: 5, danger: 8 }
    },
};

const getGradientColor = (type, value) => {
    const tips = SETTING_TIPS[type];
    if (!tips || !tips.thresholds) return theme.colors.success;
    const { warning, danger } = tips.thresholds;
    if (value >= danger) return theme.colors.error;
    if (value >= warning) return theme.colors.warning;
    return theme.colors.success;
};

const getLevelText = (type, value) => {
    const tips = SETTING_TIPS[type];
    if (!tips) return '';
    for (const [level, range] of Object.entries(tips)) {
        if (level === 'tip' || level === 'thresholds') continue;
        if (value >= range.min && value <= range.max) {
            return range.label;
        }
    }
    return '';
};

const TradingSettingsScreen = ({ navigation, user, onBack }) => {
    const isAdmin = useIsAdmin(user);
    const {
        tradingMode,
        refreshCounter,
        getModeText,
        getModeColor,
        isAdmin: contextIsAdmin,
        getCurrentViewMode,
    } = useTradingModeContext();

    const currentViewMode = getCurrentViewMode();

    const [settings, setSettings] = useState({
        trade_amount: 100.0,
        position_size_percentage: 10.0,
        take_profit_pct: 5.0,
        stop_loss_pct: 2.0,
        trailing_distance: 3.0,
        max_positions: 5,
        trading_enabled: true,
    });

    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [hasChanges, setHasChanges] = useState(false);
    const [originalSettings, setOriginalSettings] = useState(null);
    const [showAdvanced, setShowAdvanced] = useState(false);

    const isMountedRef = useRef(true);

    useEffect(() => {
        isMountedRef.current = true;
        return () => {
            isMountedRef.current = false;
        };
    }, []);

    const loadSettings = useCallback(async () => {
        if (!isMountedRef.current) return;

        try {
            if (isMountedRef.current) {
                setLoading(true);
            }

            if (!user?.id) {
                if (isMountedRef.current) {
                    setOriginalSettings(settings);
                    setLoading(false);
                }
                return;
            }

            const cachedSettings = await AsyncStorage.getItem(`trading_settings_${user.id}`);
            if (cachedSettings && isMountedRef.current) {
                try {
                    const parsed = JSON.parse(cachedSettings);
                    setSettings(parsed);
                    setOriginalSettings(parsed);
                } catch (parseError) {
                    console.warn('[CRASH_PREVENTION] فشل تحليل إعدادات التداول المخزنة:', parseError);
                    // استمر بدون الإعدادات المخزنة - سيتم جلبها من الخادم
                }
            }

            const authToken = await AsyncStorage.getItem('authToken');
            if (!authToken) {
                if (isMountedRef.current) {
                    setLoading(false);
                }
                return;
            }

            if (!isMountedRef.current) return;

            await DatabaseApiService.initialize();

            if (!isMountedRef.current) return;

            const apiData = await DatabaseApiService.getSettings(
                user.id,
                isAdmin ? currentViewMode : null
            );

            if (!isMountedRef.current) return;

            if (apiData?.success && apiData?.data) {
                const apiSettings = apiData.data;
                const newSettings = {
                    trade_amount: apiSettings.tradeAmount || apiSettings.trade_amount || 100.0,
                    position_size_percentage: apiSettings.positionSizePercentage || apiSettings.position_size_percentage || 10.0,
                    take_profit_pct: apiSettings.takeProfitPercentage || apiSettings.take_profit_pct || 5.0,
                    stop_loss_pct: apiSettings.stopLossPercentage || apiSettings.stop_loss_pct || 2.0,
                    trailing_distance: apiSettings.trailingDistance || apiSettings.trailing_distance || 3.0,
                    max_positions: apiSettings.maxConcurrentTrades || apiSettings.max_positions || 5,
                    trading_enabled: apiSettings.tradingEnabled ?? apiSettings.trading_enabled ?? false,
                };
                if (isMountedRef.current) {
                    setSettings(newSettings);
                    setOriginalSettings(newSettings);
                    await AsyncStorage.setItem(
                        `trading_settings_${user.id}`,
                        JSON.stringify(newSettings)
                    );
                }
            }
        } catch (error) {
            console.error('[ERROR] خطأ في تحميل الإعدادات:', error);
        } finally {
            if (isMountedRef.current) {
                setLoading(false);
            }
        }
    }, [user, currentViewMode, isAdmin]);

    useEffect(() => {
        loadSettings();
    }, [loadSettings]);

    useEffect(() => {
        if (refreshCounter > 0) {
            const delay = Math.random() * 500 + 500;
            const timer = setTimeout(() => {
                loadSettings();
            }, delay);
            return () => clearTimeout(timer);
        }
    }, [refreshCounter, loadSettings]);

    const saveSettings = useCallback(async () => {
        if (!isMountedRef.current) return;

        try {
            if (isMountedRef.current) {
                setSaving(true);
            }
            hapticMedium();

            const apiSettings = {
                tradeAmount: settings.trade_amount,
                positionSizePercentage: settings.position_size_percentage,
                takeProfitPercentage: settings.take_profit_pct,
                stopLossPercentage: settings.stop_loss_pct,
                trailingDistance: settings.trailing_distance,
                maxConcurrentTrades: settings.max_positions,
                tradingEnabled: settings.trading_enabled,
            };

            const response = await DatabaseApiService.updateSettings(user?.id, apiSettings);

            if (!isMountedRef.current) return;

            if (response?.success) {
                await AsyncStorage.setItem(
                    `trading_settings_${user?.id}`,
                    JSON.stringify(settings)
                );
                if (isMountedRef.current) {
                    setOriginalSettings(settings);
                    setHasChanges(false);
                    ToastService.showSuccess('تم حفظ الإعدادات بنجاح\n\n⏱️ سيتم تطبيقها في الدورة القادمة (~60 ثانية)');
                    hapticSuccess();
                }
            } else {
                if (isMountedRef.current) {
                    ToastService.showError(response?.message || 'فشل حفظ الإعدادات');
                    hapticError();
                }
            }
        } catch (error) {
            console.error('[ERROR] خطأ في حفظ الإعدادات:', error);
            if (isMountedRef.current) {
                let errorMessage = 'فشل حفظ الإعدادات';
                if (error?.code === 'ECONNABORTED' || error?.message?.includes('timeout')) {
                    errorMessage = 'انتهى وقت الانتظار. يرجى المحاولة مرة أخرى';
                } else if (error?.code === 'ERR_NETWORK' || error?.message?.includes('Network Error')) {
                    errorMessage = 'فشل الاتصال بالخادم. تحقق من اتصالك بالإنترنت';
                }
                ToastService.showError(errorMessage);
                hapticError();
            }
        } finally {
            if (isMountedRef.current) {
                setSaving(false);
            }
        }
    }, [user, settings]);

    const handleSettingChange = useCallback((key, value) => {
        setSettings(prev => ({ ...prev, [key]: value }));
        setHasChanges(true);
        hapticLight();
    }, []);

